const { DefaultAzureCredential } = require("@azure/identity");
const { SecretClient } = require("@azure/keyvault-secrets");

class SecretManager {
  constructor() {
    this._cache = new Map();
    this._cacheTTL = 300000; // 5 minutes
    this._client = null;
  }

  _getClient() {
    if (!this._client) {
      const vaultUrl = process.env.KEY_VAULT_URL;
      if (!vaultUrl) {
        throw new Error("KEY_VAULT_URL environment variable is not set");
      }
      // Use managed identity - no credentials in code
      const credential = new DefaultAzureCredential();
      this._client = new SecretClient(vaultUrl, credential);
    }
    return this._client;
  }

  async getSecret(secretName) {
    // Check cache first
    const cached = this._cache.get(secretName);
    if (cached && Date.now() - cached.timestamp < this._cacheTTL) {
      return cached.value;
    }

    const client = this._getClient();
    const secret = await client.getSecret(secretName);
    
    this._cache.set(secretName, {
      value: secret.value,
      timestamp: Date.now()
    });

    return secret.value;
  }

  async getCosmosConnectionString() {
    return this.getSecret("CosmosDBConnectionString");
  }

  clearCache() {
    this._cache.clear();
  }
}

// lib/cosmosClientFactory.js
const { CosmosClient } = require("@azure/cosmos");

class CosmosClientFactory {
  constructor(secretManager) {
    this._secretManager = secretManager;
    this._client = null;
    this._databaseId = null;
    this._containerId = null;
  }

  async initialize() {
    const connectionString = await this._secretManager.getCosmosConnectionString();
    
    this._databaseId = process.env.COSMOS_DATABASE_ID;
    this._containerId = process.env.COSMOS_CONTAINER_ID;

    if (!this._databaseId || !this._containerId) {
      throw new Error("COSMOS_DATABASE_ID and COSMOS_CONTAINER_ID must be set");
    }

    // Validate database and container IDs against allowlist pattern
    const idPattern = /^[a-zA-Z0-9_\-]{1,256}$/;
    if (!idPattern.test(this._databaseId) || !idPattern.test(this._containerId)) {
      throw new Error("Invalid database or container ID format");
    }

    this._client = new CosmosClient(connectionString);
    return this;
  }

  getContainer() {
    if (!this._client) {
      throw new Error("CosmosClientFactory not initialized. Call initialize() first.");
    }
    return this._client.database(this._databaseId).container(this._containerId);
  }

  getClient() {
    if (!this._client) {
      throw new Error("CosmosClientFactory not initialized. Call initialize() first.");
    }
    return this._client;
  }
}

// lib/checkpointManager.js
class CheckpointManager {
  constructor(container) {
    this._container = container;
    this._checkpointPartitionKey = "_system_checkpoints";
  }

  async saveCheckpoint(jobId, checkpoint) {
    const checkpointDoc = {
      id: `checkpoint_${jobId}`,
      partitionKey: this._checkpointPartitionKey,
      type: "_checkpoint",
      jobId: jobId,
      continuationToken: checkpoint.continuationToken || null,
      processedCount: checkpoint.processedCount || 0,
      lastProcessedId: checkpoint.lastProcessedId || null,
      status: checkpoint.status || "in_progress",
      updatedAt: new Date().toISOString(),
      // Never store sensitive data in checkpoint
    };

    await this._container.items.upsert(checkpointDoc);
    return checkpointDoc;
  }

  async getCheckpoint(jobId) {
    try {
      const { resource } = await this._container
        .item(`checkpoint_${jobId}`, this._checkpointPartitionKey)
        .read();
      return resource || null;
    } catch (error) {
      if (error.code === 404) {
        return null;
      }
      throw error;
    }
  }

  async deleteCheckpoint(jobId) {
    try {
      await this._container
        .item(`checkpoint_${jobId}`, this._checkpointPartitionKey)
        .delete();
    } catch (error) {
      if (error.code !== 404) {
        throw error;
      }
    }
  }
}

