// lib/documentProcessor.js
class DocumentProcessor {
  constructor(container, context) {
    this._container = container;
    this._context = context;
  }

  async processDocument(doc) {
    // Validate document structure
    if (!doc.id || !doc.type || !doc.partitionKey) {
      throw new InputValidationError(
        "Document missing required fields: id, type, partitionKey"
      );
    }

    // Process based on validated document type
    switch (doc.type) {
      case "order":
        return this._processOrder(doc);
      case "transaction":
        return this._processTransaction(doc);
      case "inventory":
        return this._processInventory(doc);
      case "customer_event":
        return this._processCustomerEvent(doc);
      default:
        throw new InputValidationError(`Unhandled document type: ${doc.type}`);
    }
  }

  async _processOrder(doc) {
    const updatedDoc = {
      ...doc,
      processedAt: new Date().toISOString(),
      status: "processed",
      _processingVersion: (doc._processingVersion || 0) + 1
    };

    // Use optimistic concurrency with ETag
    const options = {};
    if (doc._etag) {
      options.accessCondition = {
        type: "IfMatch",
        condition: doc._etag
      };
    }

    try {
      await this._container
        .item(doc.id, doc.partitionKey)
        .replace(updatedDoc, options);
    } catch (error) {
      if (error.code === 412) {
        // Precondition failed - document was modified by another process
        this._context.log.warn(
          `Concurrency conflict for document ${doc.id}. Skipping.`
        );
        return;
      }
      throw error;
    }
  }

  async _processTransaction(doc) {
    const updatedDoc = {
      ...doc,
      processedAt: new Date().toISOString(),
      status: "reconciled",
      _processingVersion: (doc._processingVersion || 0) + 1
    };

    const options = {};
    if (doc._etag) {
      options.accessCondition = {
        type: "IfMatch",
        condition: doc._etag
      };
    }

    try {
      await this._container
        .item(doc.id, doc.partitionKey)
        .replace(updatedDoc, options);
    } catch (error) {
      if (error.code === 412) {
        this._context.log.warn(
          `Concurrency conflict for transaction ${doc.id}. Skipping.`
        );
        return;
      }
      throw error;
    }
  }

  async _processInventory(doc) {
    const updatedDoc = {
      ...doc,
      lastAuditedAt: new Date().toISOString(),
      status: "audited",
      _processingVersion: (doc._processingVersion || 0) + 1
    };

    const options = {};
    if (doc._etag) {
      options.accessCondition = {
        type: "IfMatch",
        condition: doc._etag
      };
    }

    try {
      await this._container
        .item(doc.id, doc.partitionKey)
        .replace(updatedDoc, options);
    } catch (error) {
      if (error.code === 412) {
        this._context.log.warn(
          `Concurrency conflict for inventory ${doc.id}. Skipping.`
        );
        return;
      }
      throw error;
    }
  }

  async _processCustomerEvent(doc) {
    const updatedDoc = {
      ...doc,
      processedAt: new Date().toISOString(),
      status: "processed",
      _processingVersion: (doc._processingVersion || 0) + 1
    };

    const options = {};
    if (doc._etag) {
      options.accessCondition = {
        type: "IfMatch",
        condition: doc._etag
      };
    }

    try {
      await this._container
        .item(doc.id, doc.partitionKey)
        .replace(updatedDoc, options);
    } catch (error) {
      if (error.code === 412) {
        this._context.log.warn(
          `Concurrency conflict for customer event ${doc.id}. Skipping.`
        );
        return;
      }
      throw error;
    }
  }
}

