const crypto = require("crypto");

module.exports = async function (context, timer) {
  const invocationId = crypto.randomUUID();
  const startTime = Date.now();

  context.log.info(`Batch processing function started. Invocation: ${invocationId}`);

  if (timer.isPastDue) {
    context.log.warn("Timer trigger is past due. Proceeding with execution.");
  }

  let secretManager;
  let cosmosFactory;
  let container;
  let checkpointManager;

  try {
    // Initialize secure connections
    secretManager = new SecretManager();
    cosmosFactory = new CosmosClientFactory(secretManager);
    await cosmosFactory.initialize();
    
    container = cosmosFactory.getContainer();
    checkpointManager = new CheckpointManager(container);

    // Generate a deterministic job ID based on the schedule
    // This allows resuming from the same checkpoint if the function times out
    const today = new Date().toISOString().split("T")[0];
    const hour = new Date().getUTCHours();
    const jobId = `batch_${today}_${hour}`;

    context.log.info(`Job ID: ${jobId}`);

    // Check for existing checkpoint (resume capability)
    const existingCheckpoint = await checkpointManager.getCheckpoint(jobId);
    let continuationToken = null;
    let previouslyProcessed = 0;

    if (existingCheckpoint && existingCheckpoint.status === "in_progress") {
      continuationToken = existingCheckpoint.continuationToken;
      previouslyProcessed = existingCheckpoint.processedCount || 0;
      context.log.info(
        `Resuming from checkpoint. Previously processed: ${previouslyProcessed}`
      );
    }

    // Build parameterized query - never interpolate user input into queries
    const querySpec = {
      query: "SELECT * FROM c WHERE c.type IN (@type1, @type2, @type3, @type4) " +
             "AND (NOT IS_DEFINED(c.status) OR c.status = @pendingStatus) " +
             "AND c.type != @systemType",
      parameters: [
        { name: "@type1", value: "order" },
        { name: "@type2", value: "transaction" },
        { name: "@type3", value: "inventory" },
        { name: "@type4", value: "customer_event" },
        { name: "@pendingStatus", value: "pending" },
        { name: "@systemType", value: "_checkpoint" }
      ]
    };

    // Initialize processor
    const documentProcessor = new DocumentProcessor(container, context);
    const batchProcessor = new BatchProcessor(container, context, {
      batchSize: validator.validateBatchSize(process.env.BATCH_SIZE || "500"),
      maxRUPerSecond: parseInt(process.env.MAX_RU_PER_SECOND || "1000", 10),
      processingTimeoutMs: 540000 // 9 minutes - 1 minute buffer before 10-min timeout
    });

    // Process documents
    const result = await batchProcessor.processDocuments(
      querySpec,
      (doc) => documentProcessor.processDocument(doc),
      continuationToken
    );

    // Update total count including previously processed
    result.processedCount += previouslyProcessed;

    // Save checkpoint
    if (result.completed) {
      await checkpointManager.saveCheckpoint(jobId, {
        processedCount: result.processedCount,
        status: "completed",
        continuationToken: null
      });
      context.log.info(
        `Job ${jobId} completed successfully. ` +
        `Total processed: ${result.processedCount}, ` +
        `Errors: ${result.errorCount}, ` +
        `Elapsed: ${result.elapsedSeconds}s, ` +
        `RU consumed: ${Math.round(result.totalRequestCharge)}`
      );
    } else if (result.timedOut) {
      await checkpointManager.saveCheckpoint(jobId, {
        processedCount: result.processedCount,
        continuationToken: result.continuationToken,
        status: "in_progress"
      });
      context.log.warn(
        `Job ${jobId} timed out. Will resume on next invocation. ` +
        `Processed so far: ${result.processedCount}, ` +
        `Errors: ${result.errorCount}`
      );
    } else if (result.fatalError) {
      await checkpointManager.saveCheckpoint(jobId, {
        processedCount: result.processedCount,
        continuationToken: result.continuationToken,
        status: "failed"
      });
      context.log.error(
        `Job ${jobId} failed with fatal error. ` +
        `Processed: ${result.processedCount}, ` +
        `Errors: ${result.errorCount}`
      );
    }

    // Log summary (no sensitive data)
    context.log.info(JSON.stringify({
      invocationId,
      jobId,
      completed: result.completed,
      processedCount: result.processedCount,
      errorCount: result.errorCount,
      elapsedSeconds: result.elapsedSeconds,
      totalRU: Math.round(result.totalRequestCharge),
      timedOut: result.timedOut || false,
      fatalError: result.fatalError || false
    }));

  } catch (error) {
    const elapsedSeconds = Math.round((Date.now() - startTime) / 1000);
    
    // Log error without leaking sensitive details
    context.log.error(
      `Batch processing function failed after ${elapsedSeconds}s. ` +
      `Error type: ${error.name}. ` +
      `Invocation: ${invocationId}`
    );

    // Don't log connection strings, tokens, or stack traces with sensitive info
    if (error.isValidationError) {
      context.log.error(`Validation error: ${error.message}`);
    }

    throw error;
  } finally {
    // Clean up secret cache
    if (secretManager) {
      secretManager.clearCache();
    }
  }
};

